
.cw-root {
  width: 100%;
  position: relative;
  color: var(--cw-text);
}

.cw-anchor {
  width: 100%;
  aspect-ratio: 16 / 1;
  opacity: 0;
  pointer-events: none;
}

.cw-panel {
  width: min(100%, 780px);
  border: 1px solid var(--cw-border);
  border-radius: 24px;
  background: var(--cw-bg);
  box-shadow: var(--cw-shadow);
  backdrop-filter: blur(20px);
  transition:
    transform var(--cw-ease),
    box-shadow var(--cw-ease),
    border-color var(--cw-ease);
  overflow: hidden;
}

.cw-panel--floating {
  position: fixed;
  z-index: 999;
}

.cw-panel--inline {
  position: relative;
  margin: 0 auto;
}

.cw-panel.is-dragging {
  box-shadow: 0 24px 60px rgba(2, 6, 23, 0.5);
  transform: scale(1.01);
}

.cw-panel__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 18px 20px 14px;
  cursor: grab;
  background: linear-gradient(180deg, rgba(251, 191, 36, 0.14), rgba(255, 255, 255, 0));
}

.cw-panel--inline .cw-panel__header {
  cursor: default;
}

.cw-header__brand,
.cw-modal__header,
.cw-character-card__header,
.cw-relation-column__header,
.cw-world-chip,
.cw-action-row,
.cw-header__actions,
.cw-split-grid,
.cw-progress-card,
.cw-grid,
.cw-inventory-grid,
.cw-tag-list,
.cw-relation-row {
  display: flex;
}

.cw-header__brand,
.cw-modal__header,
.cw-character-card__header,
.cw-relation-column__header,
.cw-world-chip,
.cw-action-row,
.cw-header__actions,
.cw-relation-row {
  align-items: center;
}

.cw-grid,
.cw-inventory-grid,
.cw-relation-grid,
.cw-character-list {
  display: grid;
}

.cw-header__brand {
  gap: 14px;
}

.cw-header__moon,
.cw-fab__moon {
  border-radius: 999px;
  background: radial-gradient(circle at 30% 30%, #fff7d2, #fbbf24 45%, #7c5b13 100%);
  box-shadow:
    0 0 22px rgba(251, 191, 36, 0.55),
    inset -8px -6px 10px rgba(0, 0, 0, 0.35);
}

.cw-header__moon {
  width: 46px;
  aspect-ratio: 1;
}

.cw-panel__eyebrow,
.cw-section__eyebrow,
.cw-mini-label,
.cw-world-chip__label,
.cw-stat-card__label,
.cw-progress-card__label,
.cw-fab__sub {
  margin: 0;
  color: var(--cw-text-soft);
  letter-spacing: 0.12em;
  text-transform: uppercase;
  font-size: 11px;
}

.cw-panel__title,
.cw-section__title,
.cw-modal__title,
.cw-progress-card__title,
.cw-glass-card__title {
  margin: 0;
  font-family: var(--cw-font-display);
}

.cw-panel__title {
  font-size: 25px;
}

.cw-header__actions {
  gap: 10px;
}

.cw-icon-btn,
.cw-action-btn {
  border: 1px solid var(--cw-border);
  color: var(--cw-text);
  background: rgba(8, 15, 29, 0.54);
  transition:
    transform var(--cw-ease),
    background var(--cw-ease),
    border-color var(--cw-ease);
}

.cw-icon-btn {
  width: 40px;
  aspect-ratio: 1;
  border-radius: 14px;
  cursor: pointer;
}

.cw-icon-btn:hover,
.cw-action-btn:hover,
.cw-fab:hover {
  transform: translateY(-1px);
  background: rgba(251, 191, 36, 0.18);
  border-color: rgba(251, 191, 36, 0.5);
}

.cw-world-strip,
.cw-section {
  padding: 0 20px 20px;
}

.cw-world-strip {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 10px;
}

.cw-world-chip {
  justify-content: space-between;
  gap: 12px;
  border: 1px solid var(--cw-border-soft);
  background: rgba(255, 255, 255, 0.04);
  border-radius: 16px;
  padding: 10px 12px;
}

.cw-world-chip__value,
.cw-stat-card__value,
.cw-progress-card__value,
.cw-mini-value,
.cw-inventory-card__value,
.cw-action-btn span,
.cw-relation-row span {
  color: var(--cw-accent-soft);
}

.cw-world-chip__value,
.cw-stat-card__value,
.cw-progress-card__value,
.cw-mini-value,
.cw-inventory-card__value {
  font-weight: 600;
}

.cw-section {
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.cw-section__heading {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: 12px;
}

.cw-progress-card {
  flex-wrap: wrap;
  align-items: center;
  gap: 14px;
  padding: 18px;
  border-radius: 20px;
  background: linear-gradient(135deg, rgba(125, 211, 252, 0.12), rgba(251, 191, 36, 0.16));
  border: 1px solid rgba(125, 211, 252, 0.28);
}

.cw-progress-card__title {
  font-size: 24px;
}

.cw-progress-card__value {
  margin-left: auto;
  font-size: 28px;
}

.cw-progress-card__bar {
  width: 100%;
  height: 10px;
  overflow: hidden;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.14);
}

.cw-progress-card__fill {
  display: block;
  height: 100%;
  border-radius: inherit;
  background: linear-gradient(90deg, var(--cw-cyan), var(--cw-accent));
}

.cw-grid {
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 12px;
}

.cw-stat-card,
.cw-glass-card,
.cw-inventory-card,
.cw-character-card,
.cw-relation-column,
.cw-modal__card {
  border-radius: 20px;
  border: 1px solid var(--cw-border-soft);
  background: rgba(6, 12, 24, 0.56);
  backdrop-filter: blur(16px);
}

.cw-stat-card,
.cw-glass-card,
.cw-inventory-card,
.cw-character-card,
.cw-relation-column {
  padding: 14px;
}

.cw-stat-card__value {
  margin: 6px 0 0;
  font-size: 16px;
  color: var(--cw-text);
}

.cw-accordion {
  border: 1px solid var(--cw-border-soft);
  border-radius: 20px;
  background: rgba(6, 12, 24, 0.42);
}

.cw-accordion summary {
  list-style: none;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 16px;
  cursor: pointer;
}

.cw-accordion summary::-webkit-details-marker {
  display: none;
}

.cw-accordion__body {
  padding: 0 16px 16px;
}

.cw-split-grid {
  gap: 12px;
}

.cw-split-grid > * {
  flex: 1 1 0;
}

.cw-split-grid--treasures {
  align-items: stretch;
}

.cw-description,
.cw-inventory-card__meta,
.cw-character-card p,
.cw-relation-row p,
.cw-empty,
.cw-empty-state {
  margin: 8px 0 0;
  color: var(--cw-text-soft);
  line-height: 1.5;
}

.cw-tag-list {
  flex-wrap: wrap;
  gap: 8px;
  margin-top: 8px;
}

.cw-tag {
  padding: 6px 10px;
  border-radius: 999px;
  border: 1px solid rgba(125, 211, 252, 0.18);
  background: rgba(125, 211, 252, 0.09);
  color: var(--cw-text);
  font-size: 12px;
}

.cw-inventory-grid {
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 12px;
}

.cw-inventory-card__value {
  margin: 8px 0 0;
  font-size: 26px;
}

.cw-action-row {
  gap: 12px;
}

.cw-action-btn {
  flex: 1 1 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 14px 16px;
  border-radius: 18px;
  cursor: pointer;
}

.cw-action-btn span,
.cw-relation-row span {
  font-weight: 700;
}

.cw-modal {
  position: fixed;
  inset: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 20px;
  background: rgba(2, 6, 23, 0.48);
  backdrop-filter: blur(12px);
}

.cw-modal__card {
  width: min(100%, 920px);
  padding: 18px;
}

.cw-modal__header {
  justify-content: space-between;
  gap: 12px;
  margin-bottom: 14px;
}

.cw-character-list {
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
}

.cw-character-card__header,
.cw-relation-column__header,
.cw-relation-row {
  justify-content: space-between;
  gap: 12px;
}

.cw-character-card__header h4,
.cw-relation-column h4 {
  margin: 0;
  font-size: 16px;
}

.cw-character-card__header span,
.cw-relation-column__header span {
  color: var(--cw-accent-soft);
  font-size: 13px;
}

.cw-relation-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
}

.cw-relation-column {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.cw-relation-row {
  padding: 12px 0;
  border-top: 1px solid rgba(148, 163, 184, 0.12);
}

.cw-relation-row:first-of-type {
  border-top: none;
}

.cw-fab {
  position: fixed;
  right: 22px;
  top: 110px;
  z-index: 999;
  width: 88px;
  aspect-ratio: 1;
  border-radius: 999px;
  border: 1px solid rgba(251, 191, 36, 0.45);
  background: radial-gradient(circle at 30% 30%, rgba(255, 255, 255, 0.2), rgba(15, 23, 42, 0.92));
  box-shadow:
    0 0 28px rgba(251, 191, 36, 0.28),
    0 18px 30px rgba(2, 6, 23, 0.4);
  color: var(--cw-text);
  cursor: pointer;
  overflow: hidden;
}

.cw-fab__halo {
  position: absolute;
  inset: 12px;
  border-radius: inherit;
  border: 1px solid rgba(125, 211, 252, 0.26);
  animation: haloPulse 2.8s ease-in-out infinite;
}

.cw-fab__moon {
  position: absolute;
  top: 16px;
  left: 50%;
  width: 28px;
  aspect-ratio: 1;
  transform: translateX(-50%);
}

.cw-fab__label,
.cw-fab__sub {
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  width: calc(100% - 20px);
  text-align: center;
}

.cw-fab__label {
  bottom: 24px;
  font-size: 13px;
  font-weight: 700;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.cw-fab__sub {
  bottom: 10px;
  font-size: 10px;
}

@keyframes haloPulse {
  0%,
  100% {
    transform: scale(0.92);
    opacity: 0.45;
  }

  50% {
    transform: scale(1);
    opacity: 0.9;
  }
}

@media (max-width: 900px) {
  .cw-panel {
    width: min(100%, calc(100% - 24px));
  }

  .cw-world-strip,
  .cw-grid,
  .cw-inventory-grid,
  .cw-character-list,
  .cw-relation-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .cw-action-row,
  .cw-split-grid,
  .cw-panel__header {
    flex-direction: column;
    align-items: stretch;
  }

  .cw-progress-card__value {
    margin-left: 0;
  }
}

@media (max-width: 640px) {
  .cw-world-strip,
  .cw-grid,
  .cw-inventory-grid,
  .cw-character-list,
  .cw-relation-grid {
    grid-template-columns: minmax(0, 1fr);
  }

  .cw-panel__title {
    font-size: 22px;
  }

  .cw-fab {
    width: 74px;
    right: 14px;
    top: 86px;
  }
}
